/* Test driver */
import java.util.EnumSet;
public class Main {
    public static void main(String[] args) {
        FileSystem fs = new FileSystem();
        File f = fs.createFile("/etc/conf","old");
        f.setPermissions(EnumSet.of(Permission.READ));
        boolean denied = false;
        try { f.setContent("new"); } catch (SecurityException e) { denied = true; }
        System.out.println(denied ? "OK_WRITE_DENIED" : "FAIL");
        System.out.println(f.getContent().equals("old") ? "OK_CONTENT_UNCHANGED" : "FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        FileSystem fs = new FileSystem();
        fs.createFile("/d/a.txt","aaa");
        fs.createFile("/d/b.txt","bb");
        boolean removed = fs.delete("/d/a.txt");
        System.out.println(removed ? "OK_DELETED" : "FAIL");
        System.out.println(fs.ls("/d").size() == 1 ? "OK_LS_AFTER_1" : "FAIL");
        boolean caught = false;
        try { fs.resolve("/d/a.txt"); } catch (IllegalArgumentException e) { caught = true; }
        System.out.println(caught ? "OK_RESOLVE_THROWS" : "FAIL");
    }
}

